234: // generatePodSandboxWindowsConfig generates WindowsPodSandboxConfig from v1.Pod.
235: // On Windows this will get called in addition to LinuxPodSandboxConfig because not all relevant fields have been added to
236: // WindowsPodSandboxConfig at this time.
237: func (m *kubeGenericRuntimeManager) generatePodSandboxWindowsConfig(pod *v1.Pod) (*runtimeapi.WindowsPodSandboxConfig, error) {
238: 	wc := &runtimeapi.WindowsPodSandboxConfig{
239: 		SecurityContext: &runtimeapi.WindowsSandboxSecurityContext{},
240: 	}
241: 
242: 	// If all of the containers in a pod are HostProcess containers, set the pod's HostProcess field
243: 	// explicitly because the container runtime requires this information at sandbox creation time.
244: 	if kubecontainer.HasWindowsHostProcessContainer(pod) {
245: 		// At present Windows all containers in a Windows pod must be HostProcess containers
246: 		// and HostNetwork is required to be set.
247: 		if !kubecontainer.AllContainersAreWindowsHostProcess(pod) {
248: 			return nil, fmt.Errorf("pod must not contain both HostProcess and non-HostProcess containers")
249: 		}
250: 
251: 		if !kubecontainer.IsHostNetworkPod(pod) {
252: 			return nil, fmt.Errorf("hostNetwork is required if Pod contains HostProcess containers")
253: 		}
254: 
255: 		wc.SecurityContext.HostProcess = true
256: 	}
257: 
258: 	sc := pod.Spec.SecurityContext
259: 	if sc == nil || sc.WindowsOptions == nil {
260: 		return wc, nil
261: 	}
262: 
263: 	wo := sc.WindowsOptions
264: 	if wo.GMSACredentialSpec != nil {
265: 		wc.SecurityContext.CredentialSpec = *wo.GMSACredentialSpec
266: 	}
267: 
268: 	if wo.RunAsUserName != nil {
269: 		wc.SecurityContext.RunAsUsername = *wo.RunAsUserName
270: 	}
271: 
272: 	if kubecontainer.HasWindowsHostProcessContainer(pod) {
273: 
274: 		if wo.HostProcess != nil && !*wo.HostProcess {
275: 			return nil, fmt.Errorf("pod must not contain any HostProcess containers if Pod's WindowsOptions.HostProcess is set to false")
276: 		}
277: 	}
278: 
279: 	return wc, nil
280: }
