282: // getKubeletSandboxes lists all (or just the running) sandboxes managed by kubelet.
283: func (m *kubeGenericRuntimeManager) getKubeletSandboxes(ctx context.Context, all bool) ([]*runtimeapi.PodSandbox, error) {
284: 	logger := klog.FromContext(ctx)
285: 	var filter *runtimeapi.PodSandboxFilter
286: 	if !all {
287: 		readyState := runtimeapi.PodSandboxState_SANDBOX_READY
288: 		filter = &runtimeapi.PodSandboxFilter{
289: 			State: &runtimeapi.PodSandboxStateValue{
290: 				State: readyState,
291: 			},
292: 		}
293: 	}
294: 
295: 	resp, err := m.runtimeService.ListPodSandbox(ctx, filter)
296: 	if err != nil {
297: 		logger.Error(err, "Failed to list pod sandboxes")
298: 		return nil, err
299: 	}
300: 
301: 	return resp, nil
302: }
