304: // determinePodSandboxIP determines the IP addresses of the given pod sandbox.
305: func (m *kubeGenericRuntimeManager) determinePodSandboxIPs(ctx context.Context, podNamespace, podName string, podSandbox *runtimeapi.PodSandboxStatus) []string {
306: 	logger := klog.FromContext(ctx)
307: 	podIPs := make([]string, 0)
308: 	if podSandbox.Network == nil {
309: 		logger.Info("Pod Sandbox status doesn't have network information, cannot report IPs", "pod", klog.KRef(podNamespace, podName))
310: 		return podIPs
311: 	}
312: 
313: 	// ip could be an empty string if runtime is not responsible for the
314: 	// IP (e.g., host networking).
315: 
316: 	// pick primary IP
317: 	if len(podSandbox.Network.Ip) != 0 {
318: 		if netutils.ParseIPSloppy(podSandbox.Network.Ip) == nil {
319: 			logger.Info("Pod Sandbox reported an unparseable primary IP", "pod", klog.KRef(podNamespace, podName), "IP", podSandbox.Network.Ip)
320: 			return nil
321: 		}
322: 		podIPs = append(podIPs, podSandbox.Network.Ip)
323: 	}
324: 
325: 	// pick additional ips, if cri reported them
326: 	for _, podIP := range podSandbox.Network.AdditionalIps {
327: 		if nil == netutils.ParseIPSloppy(podIP.Ip) {
328: 			logger.Info("Pod Sandbox reported an unparseable additional IP", "pod", klog.KRef(podNamespace, podName), "IP", podIP.Ip)
329: 			return nil
330: 		}
331: 		podIPs = append(podIPs, podIP.Ip)
332: 	}
333: 
334: 	return podIPs
335: }
