337: // getPodSandboxID gets the sandbox id by podUID and returns ([]sandboxID, error).
338: // Param state could be nil in order to get all sandboxes belonging to same pod.
339: func (m *kubeGenericRuntimeManager) getSandboxIDByPodUID(ctx context.Context, podUID kubetypes.UID, state *runtimeapi.PodSandboxState) ([]string, error) {
340: 	logger := klog.FromContext(ctx)
341: 	filter := &runtimeapi.PodSandboxFilter{
342: 		LabelSelector: map[string]string{types.KubernetesPodUIDLabel: string(podUID)},
343: 	}
344: 	if state != nil {
345: 		filter.State = &runtimeapi.PodSandboxStateValue{
346: 			State: *state,
347: 		}
348: 	}
349: 	sandboxes, err := m.runtimeService.ListPodSandbox(ctx, filter)
350: 	if err != nil {
351: 		logger.Error(err, "Failed to list sandboxes for pod", "podUID", podUID)
352: 		return nil, err
353: 	}
354: 
355: 	if len(sandboxes) == 0 {
356: 		return nil, nil
357: 	}
358: 
359: 	// Sort with newest first.
360: 	sandboxIDs := make([]string, len(sandboxes))
361: 	sort.Sort(podSandboxByCreated(sandboxes))
362: 	for i, s := range sandboxes {
363: 		sandboxIDs[i] = s.Id
364: 	}
365: 
366: 	return sandboxIDs, nil
367: }
