369: // GetPortForward gets the endpoint the runtime will serve the port-forward request from.
370: func (m *kubeGenericRuntimeManager) GetPortForward(ctx context.Context, podName, podNamespace string, podUID kubetypes.UID, ports []int32) (*url.URL, error) {
371: 	sandboxIDs, err := m.getSandboxIDByPodUID(ctx, podUID, nil)
372: 	if err != nil {
373: 		return nil, fmt.Errorf("failed to find sandboxID for pod %s: %v", format.PodDesc(podName, podNamespace, podUID), err)
374: 	}
375: 	if len(sandboxIDs) == 0 {
376: 		return nil, fmt.Errorf("failed to find sandboxID for pod %s", format.PodDesc(podName, podNamespace, podUID))
377: 	}
378: 	req := &runtimeapi.PortForwardRequest{
379: 		PodSandboxId: sandboxIDs[0],
380: 		Port:         ports,
381: 	}
382: 	resp, err := m.runtimeService.PortForward(ctx, req)
383: 	if err != nil {
384: 		return nil, err
385: 	}
386: 	return url.Parse(resp.Url)
387: }
